sys_security_acl.script:
if (gs.hasRole('x_2097092_linq.platform_admin')) {
  answer = true;
} else if (gs.hasRole('x_2097092_linq.college_admin')) {
  // College admin reads memberships of clubs in their college
  var userCollege = gs.getUser().getRecord().getValue('u_college');
  var clubGr = new GlideRecord('x_2097092_linq_club');
  clubGr.get(current.getValue('club'));
  answer = (clubGr.getValue('college') == userCollege);
} else {
  // club_admin/club_member: read memberships of clubs they belong to
  var gr = new GlideRecord('x_2097092_linq_club_membership');
  gr.addQuery('member', gs.getUserID());
  gr.addQuery('club', current.getValue('club'));
  gr.addQuery('status', 'active');
  gr.query();
  answer = gr.hasNext();
}
